-- =====================================================
-- VERIFY
-- =====================================================

SELECT 
    nc.cohort_number,
    nt.name,
    nt.role,
    CASE WHEN sg.grade_id IS NULL THEN 'STILL MISSING' ELSE 'FIXED' END as subpillar_status
FROM trainee_grades tg
JOIN niche_training nt ON tg.trainee_id = nt.id
JOIN niche_cohorts nc ON tg.cohort_id = nc.id
LEFT JOIN niche_subpillar_grades sg ON sg.grade_id = tg.id
WHERE nc.cohort_number IN (1, 2)
ORDER BY nc.cohort_number, nt.name;
